    13→export const execute = async (event: any, context: Context, callback: any) => {
    14→  Console.prepareStream(event, context)
    15→  const callbackSTP = new Callback(event, callback, context);
    16→
    17→  const record = typeof event === "string" ? JSON.parse(event).Records[0] : event.Records[0];
    18→
    19→  try {
    20→    const sqs = new SQS({
    21→      region: "sa-east-1",
    22→    });
    23→    
    24→    const sqsService = new SqsService(
    25→      sqs,
    26→      process.env.QUEUE_APP_ISENCAO_MENSALIDADE_CARTAO!
    27→    );
    28→
    29→    const sqsDLQService = new SqsService(
    30→      sqs,
    31→      process.env.QUEUE_APP_ISENCAO_MENSALIDADE_CARTAO_ERRO!
    32→    );
    33→
    34→    const sqsEmailService = new SqsService(
    35→      sqs,
    36→      process.env.QUEUE_APP_ISENCAO_MENSALIDADE_CARTAO_EMAIL!
    37→    );
    38→    const graphQlService = new GraphQlService();
    39→    const getUser = new GetUserNRC(graphQlService);
    40→    const getAccessPoint = new GetAccessPoint(graphQlService);
    41→    const postPromotion = new PostPromotion(graphQlService);
    42→ 
    43→
    44→    const processUserPromotion = new ProcessUserPromotion(
    45→      getUser,
    46→      getAccessPoint,
    47→      postPromotion,
    48→      sqsDLQService,
    49→      sqsEmailService,
    50→      sqsService
    51→    );
    52→
    53→    const processPromotion = await processUserPromotion.execute(record);
    54→
    55→    const response = {
    56→      status: {
    57→        codigoRetorno: 0,
    58→        mensagem: processPromotion,
    59→      },
    60→    };
    61→
    62→    return callbackSTP.send(null, response);
    63→  } catch (error) {
    64→    const response = {
    65→      status: {
    66→        codigoRetorno: -1,
    67→        mensagem: String(error),
    68→      },
    69→    };
    70→    callbackSTP.send(response);
    71→  }
    72→};
