     1→import { SQS, DeleteMessageCommand} from '@aws-sdk/client-sqs';
     2→import { Console } from 'libStpInvoke';
     3→
     4→export class SqsService {
     5→  private sqs: SQS;
     6→  private url: string;
     7→
     8→  constructor(sqs: SQS, url: string) {
     9→    this.sqs = sqs;
    10→    this.url = url;
    11→  }
    12→
    13→  async sendToSQS(message: Object): Promise<void> {
    14→    try {
    15→      await this.sqs
    16→        .sendMessage({
    17→          QueueUrl: this.url,
    18→          MessageBody: JSON.stringify(message), 
    19→        });
    20→    } catch (error) {
    21→      Console.error('Failed to send message to SQS:', error);
    22→      throw error; 
    23→    }
    24→  }
    25→
    26→  async deleteFromSQS(receiptHandle: string): Promise<void> {
    27→    try {
    28→      await this.sqs.send(new DeleteMessageCommand({
    29→        QueueUrl: this.url,
    30→        ReceiptHandle: receiptHandle,
    31→      }));
    32→    } catch (error) {
    33→      Console.error('Failed to delete message from SQS:', error);
    34→      throw error;
    35→    }
    36→  }
    37→}
