import { DynamoDBService } from "../../infrastructure";
import { PromotionUI } from "../../models/Promotions";
import { SqsService } from "../../infrastructure/index";
import { SQS } from "@aws-sdk/client-sqs";
import { Console } from "libStpInvoke";

export default class CreatePromotion {
    constructor(
        private dynamodbService: DynamoDBService
    ) {}

    async execute(promotion: PromotionUI) {
        const promotionKey = { PK: `PROMOTION#${promotion.promotionCodeCbill}` };

        try {
            const existingPromotion = await this.dynamodbService.getItem('FINTECH-Promocoes', promotionKey);

            if (existingPromotion) {
                await this.updatePromotion(promotionKey, promotion);
            } else {
                await this.dynamodbService.putItem('FINTECH-Promocoes', { ...promotion });
            }
        } catch (error) {
            Console.error('Erro ao criar ou atualizar promoção', error);
            throw error;
        }
    }

    private async updatePromotion(promotionKey: { PK: string }, promotion: PromotionUI) {
        try {
            const updateExpressionParts: string[] = [];
            const expressionAttributeValues: Record<string, any> = {};
            const expressionAttributeNames: Record<string, string> = {};

            for (const [key, value] of Object.entries(promotion)) {
                if (value !== undefined && value !== null && key !== 'PK') {
                    if (Array.isArray(value) && value.length > 0 && typeof value[0] === 'object' && value[0].id) {
                        const fieldPath = `#${key}.items`;
                        expressionAttributeNames[`#${key}`] = key;

                        value.forEach((item, index) => {
                            const itemKey = `:${key}${item.id}`;
                            expressionAttributeValues[itemKey] = item;
                            updateExpressionParts.push(`${fieldPath}[${index}] = ${itemKey}`);
                        });
                    } else {
                        const expressionKey = `:${key}`;
                        expressionAttributeNames[`#${key}`] = key;
                        updateExpressionParts.push(`#${key} = ${expressionKey}`);
                        expressionAttributeValues[expressionKey] = value;
                    }
                }
            }

            if (updateExpressionParts.length === 0) {
                Console.error('Nenhum campo válido encontrado no body de promoção');
                return;
            }

            const updateExpression = `SET ${updateExpressionParts.join(', ')}`;

            await this.dynamodbService.updateItem(
                'FINTECH-Promocoes',
                promotionKey,
                updateExpression,
                expressionAttributeValues,
                expressionAttributeNames
            );

            Console.info('Promoção atualizada com sucesso');
        } catch (error) {
            Console.error('Erro ao atualizar promoção', error);
            throw error;
        }
    }

    async createPromotionToOffersInternalTest(promotion: any){
        const sqs = new SQS({
            region: "sa-east-1",
        });

        const sqsService = new SqsService(
            sqs,
            process.env.QUEUE_FINTECH_QUEUE_SEND_PROMOTION_TO_SAVE!
        );

        Console.info('DATA TEST: ', promotion)
        await sqsService.sendToSQS(promotion);
    }
}

